import React, { useEffect, useState } from "react";
import api from "../api";

function UserDashboard() {
  const [user, setUser] = useState(null);
  const [orders, setOrders] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState("");

  const storedUser = JSON.parse(localStorage.getItem("user"));

  // Fetch user and their orders
  const fetchData = async () => {
    try {
      setLoading(true);
      const [userRes, ordersRes] = await Promise.all([
        api.post(`/user/${storedUser.id}`),
        api.get(`/orders/user/${storedUser.id}`), // endpoint to get only this user's orders
      ]);

      setUser(userRes.data);
      setOrders(ordersRes.data);
    } catch (err) {
      console.error(err);
      setError("Failed to load dashboard. Please try again.");
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    fetchData();
  }, []);

  if (loading) return <div className="text-center mt-5">Loading...</div>;
  if (error) return <div className="text-center mt-5 text-danger">{error}</div>;

  // Calculate most ordered food
  const foodMap = {};
  orders.forEach((order) => {
    order.items.forEach((item) => {
      if (foodMap[item.food._id]) {
        foodMap[item.food._id].quantity += item.quantity;
      } else {
        foodMap[item.food._id] = {
          ...item.food,
          quantity: item.quantity,
        };
      }
    });
  });

  const mostOrderedFood = Object.values(foodMap).sort(
    (a, b) => b.quantity - a.quantity
  )[0];

  return (
    <div className="container mt-4">
      {/* User Details */}
      <div className="card shadow-sm mb-4 p-3 text-center">
        <img
          src="https://via.placeholder.com/100"
          alt="avatar"
          className="rounded-circle mb-2"
        />
        <h5>{user.name}</h5>
        <p className="mb-1">🎓 {user.Degree}</p>
        <p className="text-muted small mb-2">Roll No: {user.RollNo}</p>
        <span
          className={`badge ${user.role === "admin" ? "bg-danger" : "bg-primary"}`}
        >
          {user.role.toUpperCase()}
        </span>
      </div>

      {/* Stats */}
      <div className="row g-3 mb-4">
        <div className="col-md-6">
          <div className="card shadow-sm text-center p-3">
            <h5>Total Orders</h5>
            <p className="display-6 fw-bold">{orders.length}</p>
          </div>
        </div>
        <div className="col-md-6">
          <div className="card shadow-sm text-center p-3">
            <h5>Most Ordered Food</h5>
            {mostOrderedFood ? (
              <>
                <img
                  src={mostOrderedFood.img}
                  alt={mostOrderedFood.name}
                  className="img-fluid rounded mb-2"
                  style={{ maxHeight: "120px", objectFit: "cover" }}
                />
                <p className="fw-bold">{mostOrderedFood.name}</p>
                <small className="text-muted">× {mostOrderedFood.quantity} times</small>
              </>
            ) : (
              <p>-</p>
            )}
          </div>
        </div>
      </div>

      {/* Ordered Foods List */}
      <div className="card shadow-sm p-3">
        <h5 className="mb-3">Your Ordered Foods</h5>
        {Object.values(foodMap).length === 0 ? (
          <p className="text-muted">You haven't ordered anything yet.</p>
        ) : (
          <div className="row g-3">
            {Object.values(foodMap).map((food) => (
              <div key={food._id} className="col-md-3 text-center">
                <img
                  src={food.img}
                  alt={food.name}
                  className="img-fluid rounded mb-2"
                  style={{ height: "100px", objectFit: "cover" }}
                />
                <p className="mb-0 fw-bold">{food.name}</p>
                <small className="text-muted">× {food.quantity}</small>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  );
}

export default UserDashboard;
